rows = value or []
r = rows[0] if rows else {}
return {"Id": r.get("Id"), "ItemPartNumber": r.get("ItemPartNumber") or "", "ItemDescription": r.get("ItemDescription") or "", "AccumulatedParts": r.get("AccumulatedParts") or 0, "TargetParts": r.get("TargetParts") or 0, "ClosedTrays": r.get("ClosedTrays") or 0, "TraysPerContainer": r.get("TraysPerContainer") or 0, "PartsPerTray": r.get("PartsPerTray") or 0, "IsSerialized": r.get("IsSerialized") or False}

rows = value or []
if not rows:
	return "(none at this cell)"
totals = {}
order = []
for r in rows:
	k = r.get("ItemPartNumber") or "?"
	if k not in totals:
		totals[k] = 0
		order.append(k)
	totals[k] = totals[k] + (r.get("PieceCount") or 0)
return "   |   ".join(["%s: %d pcs" % (k, totals[k]) for k in order])

